    private void errorProcess(HttpSession session, RagicBundle bundle, String apname) {
        session.setAttribute(PROCESSKEY, "F" +
                "We have a problem processing your uploaded file. " +
                "Please convert it into a different format or contact support@ragic.com" +
                "<br/><input type='button' value='" + bundle.getString("cancel") + "' size='20' onclick=\"showFloatingMain();wizardReset('" + apname + "');\" />");
        session.removeAttribute(PROCESSKEYUSER);
    }


    private String getFilePath(final File destDir, final String fileName) {
        final List<String> folderList = new ArrayList<>();
        Path zippedPath = Paths.get(destDir.getAbsolutePath());

        try {
            Files.walkFileTree(zippedPath, new FileVisitor<Path>() {
                @Override
                public FileVisitResult preVisitDirectory(Path dir, BasicFileAttributes attrs) throws IOException {
                    return FileVisitResult.CONTINUE;
                }

                @Override
                public FileVisitResult visitFile(Path file, BasicFileAttributes attrs) throws IOException {
                    if (fileName.equals(file.getFileName().toString())) {
                        folderList.add(file.toString().substring(file.toString().indexOf(destDir.toString())));
                        return FileVisitResult.TERMINATE;
                    }
                    return FileVisitResult.CONTINUE;
                }

                @Override
                public FileVisitResult visitFileFailed(Path file, IOException exc) throws IOException {
                    exc.printStackTrace();
                    return FileVisitResult.CONTINUE;
                }

                @Override
                public FileVisitResult postVisitDirectory(Path dir, IOException exc) throws IOException {
                    if (exc != null) exc.printStackTrace();
                    return FileVisitResult.CONTINUE;
                }
            });
        } catch (Exception e) {
            e.printStackTrace();
        }

        if (folderList.size() > 0) {
            return folderList.get(0);
        } else return "";
    }

    private void cleanUpload(String apname, ExtExcel mappingFile, UploadedFile zip, File destDir) {
        if (mappingFile != null) {
            mappingFile.close();
        }
        if (zip != null) {
            File zipSource = new File("cust/data/" + apname + "/upload/" + zip.getFilesystemName());
            zipSource.delete();
        }
        if (destDir != null) {
            Path zippedPath = Paths.get(destDir.getAbsolutePath());
            try {
                Files.walkFileTree(zippedPath, new FileVisitor<Path>() {
                    @Override
                    public FileVisitResult preVisitDirectory(Path dir,
                                                             BasicFileAttributes attrs) throws IOException {
                        return FileVisitResult.CONTINUE;
                    }

                    @Override
                    public FileVisitResult postVisitDirectory(Path directory, IOException ioe)
                            throws IOException {
                        try {
                            Files.delete(directory);
                            if (ioe != null) {
                                ioe.printStackTrace();
                            }
                        } catch (IOException e) {
                            e.printStackTrace();
                        }
                        return FileVisitResult.CONTINUE;
                    }

                    @Override
                    public FileVisitResult visitFile(Path file, BasicFileAttributes attributes)
                            throws IOException {
                        Files.delete(file);
                        return FileVisitResult.CONTINUE;
                    }

                    @Override
                    public FileVisitResult visitFileFailed(Path file, IOException ioe)
                            throws IOException {
                        ioe.printStackTrace();
                        return FileVisitResult.CONTINUE;
                    }
                });
            } catch (IOException e) {
                e.printStackTrace();
            }
        }
    }

