  public void _jspService(final javax.servlet.http.HttpServletRequest request, final javax.servlet.http.HttpServletResponse response)
      throws java.io.IOException, javax.servlet.ServletException {

    final java.lang.String _jspx_method = request.getMethod();
    if (!"GET".equals(_jspx_method) && !"POST".equals(_jspx_method) && !"HEAD".equals(_jspx_method) && !javax.servlet.DispatcherType.ERROR.equals(request.getDispatcherType())) {
      response.sendError(HttpServletResponse.SC_METHOD_NOT_ALLOWED, "JSPs only permit GET POST or HEAD");
      return;
    }

    final javax.servlet.jsp.PageContext pageContext;
    javax.servlet.http.HttpSession session = null;
    final javax.servlet.ServletContext application;
    final javax.servlet.ServletConfig config;
    javax.servlet.jsp.JspWriter out = null;
    final java.lang.Object page = this;
    javax.servlet.jsp.JspWriter _jspx_out = null;
    javax.servlet.jsp.PageContext _jspx_page_context = null;


    try {
      response.setContentType("text/html; charset=UTF-8");
      pageContext = _jspxFactory.getPageContext(this, request, response,
      			null, true, 8192, true);
      _jspx_page_context = pageContext;
      application = pageContext.getServletContext();
      config = pageContext.getServletConfig();
      session = pageContext.getSession();
      out = pageContext.getOut();
      _jspx_out = out;


    User user = (User) session.getAttribute("USER");
    RagicBundle bundle = (RagicBundle) session.getAttribute("RAGIC_BUNDLE");

    if (session.getAttribute(PROCESSKEYUSER) != null) {
        session.setAttribute(PROCESSKEY,
                String.format(bundle.getString("iterating_task_complete_message"), session.getAttribute(PROCESSKEYUSER)));
        return;
    }
    session.removeAttribute(PROCESSKEY);
    session.removeAttribute(PROCESSKEYUSER);


    if (!"POST".equalsIgnoreCase(request.getMethod())) return;
    String apname = request.getParameter("a"),
          path = request.getParameter("p"),
          sheetIndex = request.getParameter("si");

    if (apname == null || path == null || sheetIndex == null) return;

    int sheetIndexInt = Encoder.parseInt(sheetIndex);
    NUIForm form = AppManager.getFormPage(apname, path, sheetIndexInt);
    if (form == null) return;
    // security check
    UserFeatureAccessModule modules = UserFeatureAccessModule.configureUserAccessModule(session,apname,user);
    if (modules == null || !modules.ifAllow(Const.FUNC_MASS_FILE_UPLOAD,form,user)) return;


    session.setAttribute(PROCESSKEY, bundle.getString("massUploading"));
    session.setAttribute(PROCESSKEYUSER, user.getUserName(apname));

    int key = Encoder.parseInt(request.getParameter("key"));
    if (key == 0) {
        key = form.getField(form.getRootLocation()).getDomainId();
    }

    SIMSMultipartRequest mreq = null;
    ExtExcel mappingFile = null;
    UploadedFile zip = null;
    try {
        mreq = new SIMSMultipartRequest(request, "cust/data/" + apname + "/upload", 1024 * 1024 * 1024, "UTF-8",
                new DefaultFileRenamePolicy());

        UploadedFile uploadedMapping = (UploadedFile) mreq.getFile("mappingFile").toArray()[0];
        File _mapping = new File("cust/data/" + apname + "/upload/" + uploadedMapping.getFilesystemName());
        mappingFile = new ExtExcel(_mapping, apname);

        zip = (UploadedFile) mreq.getFile("fileZip").toArray()[0];
    } catch (Exception e) {
        e.printStackTrace();
        errorProcess(session, bundle, apname);
        cleanUpload(apname, mappingFile, zip, null);
    }
    if (mreq == null || mappingFile == null || zip == null) return;

    // unzip file
    final int BUFFER_SIZE = 4096;
    File destDir = new File("cust/tmp/" + apname + zip.getFilesystemName());
    int renameNum = 1;
    while (destDir.exists()) {
        destDir = new File("cust/tmp/" + apname + zip.getFilesystemName() + renameNum);
        renameNum++;
    }
    destDir.mkdir();
    try (ZipFile zipFile = new ZipFile (new File("cust/data/" + apname + "/upload/" + zip.getFilesystemName()))){
//        ZipInputStream zipIn = new ZipInputStream(Files.newInputStream(Paths.get("cust/data/" + apname + "/upload/" + zip.getFilesystemName())));
        Enumeration<ZipArchiveEntry> entries = zipFile.getEntries();
        InputStream inputStream;
        ZipArchiveEntry entry;
        int zipcount = 0;
        while (entries.hasMoreElements()) {
            entry = entries.nextElement();
            String filePath = destDir.getPath() + File.separator + entry.getName();
            if (!entry.isDirectory()) {
                byte[] bytesIn = new byte[BUFFER_SIZE];

                Files.createDirectories(Paths.get(filePath).getParent());

                try (BufferedOutputStream bos = new BufferedOutputStream(Files.newOutputStream(new File(filePath).toPath()))) {
                    int read;

                    inputStream = zipFile.getInputStream(entry);
                    while ((read = inputStream.read(bytesIn)) != -1) {
                        bos.write(bytesIn, 0, read);
                    }
                }
            } else {
                File dir = new File(filePath);
                dir.mkdir();
            }
//            zipIn.closeEntry();
            zipcount++;
        }
//        zipIn.close();

        if (zipcount == 0) {
            errorProcess(session, bundle, apname);
            cleanUpload(apname, mappingFile, zip, destDir);
            return;
        }
    } catch (IOException e) {
        e.printStackTrace();
    } catch (IllegalArgumentException e) {
        String errorMsg = bundle.getString("massUploadMalformed");
        session.setAttribute(PROCESSKEY, errorMsg);
        session.removeAttribute(PROCESSKEYUSER);
        return;
    }


    // do mass file import
    boolean isRowHeader = true;
    int maxColumnNum = mappingFile.getMaxColumnNum();
    int[] domainIds = new int[maxColumnNum];
    int count = 1;
    HashMap<String, String> fileRenameMapping = new HashMap<>();
    //now we ignore the fields not in the form
    //boolean hasNotMatchedDomainNames = false;
    try {
        while (mappingFile.next()) {
            if (isRowHeader) {
                for (int i = 0; i < maxColumnNum; i++) {
                    if (i == 0) {
                        domainIds[i] = key;
                    } else {
                        String headerFieldName = mappingFile.getString(i);
                        if(headerFieldName == null)continue;
                        CellInfo info = form.getFieldByName(headerFieldName);
                        if (info != null && info.isFileUpload()) {
                            domainIds[i] = info.getDomainId();
                        } else {
                            //hasNotMatchedDomainNames = true;
                            domainIds[i] = -1;
                        }
                    }
                }
                isRowHeader = false;
                continue;
            }


            APIQuery apiQuery = new APIQuery(apname, path, sheetIndexInt);
            apiQuery.setUpdateMode();
            apiQuery.setMaxRetrieveFieldSize(1024);
            apiQuery.setIfEidNaming(true);
            apiQuery.setBundle(bundle);
            for (int headerDomain : domainIds) {
                if (headerDomain != -1) {
                    apiQuery.addFetchDomains(headerDomain);
                }
            }
            HashMap<Integer, String[]> fileMap = new HashMap<>();

            //check for locks
            BDBMgr mgr = BDBMgr.getInstance(apname);
            EntryLocker lock = mgr.lockSheet(path, apiQuery.getForm().getFormName(), user, EntryLocker.API);
            if (lock != null) return;

            for (int i = 0; i < maxColumnNum; i++) {
                if (i == 0) {
                    String mappingKeyValue = mappingFile.getString(i);
                    if (mappingKeyValue.trim().length() == 0) continue;

                    String[] filterv2 = new String[1];
                    filterv2[0] = domainIds[0] + "|" + NUIFilter.OPERAND_EQ + "|" + mappingKeyValue;
                    apiQuery.setFiltersStringV2(filterv2);
                } else {
                    String fileName = mappingFile.getString(i);
                    if(fileName == null)continue;
                    if (domainIds[i] != -1 && fileName.trim().length() > 0) {
                        fileMap.put(domainIds[i], fileName.split(","));
                    }
                }
            }

            if(fileMap.size()==0)continue;

            APIResultsFull ar = apiQuery.getAPIResultsFull();
            for(APIEntry e:ar){
                    boolean entryChanged = false;
                    FileRenamePolicy renamePolicy;
                    if (FileHelper.doFileDistribute(apname)) {
                        renamePolicy = new RagicFileS3RenamePolicy(apname);
                    } else {
                        renamePolicy = new RagicFileRenamePolicy();
                    }
                    LinkedList<String> uploadFiles = new LinkedList<>();
                    for (Map.Entry<Integer, String[]> file : fileMap.entrySet()) {
                        List<String> uploadFileNames = new ArrayList<>();
                        if(form.getField(file.getKey()).isSingleFileUpload() && file.getValue().length > 1)
                            uploadFileNames.add(file.getValue()[0]);
                        else
                            uploadFileNames = Arrays.asList(file.getValue());

                        for(int i =0;i<uploadFileNames.size();i++) {
                            String trueFilePath = getFilePath(destDir, uploadFileNames.get(i));
                            if (trueFilePath.length() == 0) continue;
                            Path targetSource = Paths.get(trueFilePath);
                            //  [issue id: 11860]
                            if(fileRenameMapping.containsKey(uploadFileNames.get(i))){
                                String newFileName = fileRenameMapping.get(uploadFileNames.get(i));
                                uploadFiles.add(newFileName);
                                e.setFieldValue(file.getKey(), newFileName,(i!=0));
                                entryChanged = true;
                            } else if (Files.exists(targetSource)) {
                                String newFileName;
                                do {
                                    newFileName = renamePolicy.rename(new File(destDir.getPath() + File.separator + uploadFileNames.get(i))).getName();
                                } while (new File("cust/data/" + apname + "/upload/" + newFileName).exists());
                                Files.copy(targetSource, Paths.get("cust/data/" + apname + "/upload/" + newFileName), StandardCopyOption.REPLACE_EXISTING);
//                            Files.delete(targetSource);
                                fileRenameMapping.put(uploadFileNames.get(i), newFileName);

                                uploadFiles.add(newFileName);
                                e.setFieldValue(file.getKey(), newFileName,(i!=0));
                                entryChanged = true;
                            }
                        }
                    }

                    if (entryChanged) {
                        session.setAttribute(PROCESSKEY, bundle.getString("iterating_task_count_message") + count);
                        e.setMassUpdateMode();//async post processing especially important
                        e.setCreateHistory(true);
                        e.setIfFullTextIndex(false);//lots of attachments, we don't do index here, takes too much resources
                        e.setIfDoLnls(true); // Keep loaded value sync with source
                        e.setUploadFiles(uploadFiles);
                        e.loadAllDefaultValues(user,bundle); // load default value
                        e.save(user, bundle);

                        count++;
                    }
            }
            mgr.unlockSheet(path, apiQuery.getForm().getFormName());
        }
    } catch (Exception e) {
        e.printStackTrace();
    }

    // final clean
    cleanUpload(apname, mappingFile, zip, destDir);
    session.setAttribute(PROCESSKEY, "F<div>"+bundle.getString("iterating_task_count_message") + (count-1) + "</div>"
            +"<input type='button' value='" + bundle.getString("finish") + "' size='20' onclick=\"showFloatingMain();wizardReset('" + apname + "');\" />");
    //session.setAttribute(PROCESSKEY,
    //        (hasNotMatchedDomainNames ? bundle.getString("massUploadNotMatchedDomainName") : "" )+
    //                "<input type='button' value='" + bundle.getString("finish") + "' size='20' onclick=\"showFloatingMain();wizardReset('" + apname + "');\" />");


    final HttpSession exesession = session;
    final ScheduledThreadPoolExecutor executor = new ScheduledThreadPoolExecutor(10);
    executor.schedule(new Runnable() {
        @Override
        public void run() {
            exesession.removeAttribute(PROCESSKEY);
            exesession.removeAttribute(PROCESSKEYUSER);
        }
    }, 6, TimeUnit.SECONDS);

    } catch (java.lang.Throwable t) {
      if (!(t instanceof javax.servlet.jsp.SkipPageException)){
        out = _jspx_out;
        if (out != null && out.getBufferSize() != 0)
          try {
            if (response.isCommitted()) {
              out.flush();
            } else {
              out.clearBuffer();
            }
          } catch (java.io.IOException e) {}
        if (_jspx_page_context != null) _jspx_page_context.handlePageException(t);
        else throw new ServletException(t);
      }
    } finally {
      _jspxFactory.releasePageContext(_jspx_page_context);
    }
  }
